// Extract objection clips from WayinVideo Find Moments results
const clips = $('4. WayinVideo — Get Moments Results').item.json.data?.clips || [];

if (clips.length === 0) {
  throw new Error('No objection moments found in this recording. Try a different search query or check if the recording has audio.');
}

// Get form data
const repName = $('1. Form — Call Recording + Details').item.json['Sales Rep Name'];
const contactName = $('1. Form — Call Recording + Details').item.json['Contact Name'];
const companyName = $('1. Form — Call Recording + Details').item.json['Company Name'];
const callPurpose = $('1. Form — Call Recording + Details').item.json['Call Purpose'];
const callDate = $('1. Form — Call Recording + Details').item.json['Call Date'];
const objectionType = $('1. Form — Call Recording + Details').item.json['Objection Type to Search'];
const recordingUrl = $('1. Form — Call Recording + Details').item.json['Call Recording URL'];

// Split into individual items — one per objection moment
return clips.map((clip, index) => ({
  json: {
    clipIndex: index + 1,
    clipTitle: clip.title || `Objection Moment ${index + 1}`,
    clipDescription: clip.desc || '',
    clipScore: clip.score || 0,
    clipTags: Array.isArray(clip.tags) ? clip.tags.join(', ') : '',
    beginMs: clip.begin_ms || 0,
    endMs: clip.end_ms || 0,
    timestampStart: `${Math.floor((clip.begin_ms || 0) / 60000)}:${String(Math.floor(((clip.begin_ms || 0) % 60000) / 1000)).padStart(2, '0')}`,
    timestampEnd: `${Math.floor((clip.end_ms || 0) / 60000)}:${String(Math.floor(((clip.end_ms || 0) % 60000) / 1000)).padStart(2, '00')}`,
    repName,
    contactName,
    companyName,
    callPurpose,
    callDate,
    objectionType,
    recordingUrl
  }
}));

// Parse AI coaching output
const output = $input.first().json.output || '';

// Extract each section
const categoryMatch = output.match(/OBJECTION_CATEGORY:\s*([\s\S]*?)(?=\nWHAT_HAPPENED:|$)/);
const whatHappenedMatch = output.match(/WHAT_HAPPENED:\s*([\s\S]*?)(?=\nREP_RESPONSE_ASSESSMENT:|$)/);
const repResponseMatch = output.match(/REP_RESPONSE_ASSESSMENT:\s*([\s\S]*?)(?=\nCOACHING_NOTE:|$)/);
const coachingNoteMatch = output.match(/COACHING_NOTE:\s*([\s\S]*?)(?=\nSUGGESTED_REFRAME:|$)/);
const reframeMatch = output.match(/SUGGESTED_REFRAME:\s*([\s\S]*)$/);

const objectionCategory = categoryMatch ? categoryMatch[1].trim() : 'Other';
const whatHappened = whatHappenedMatch ? whatHappenedMatch[1].trim() : '';
const repResponseAssessment = repResponseMatch ? repResponseMatch[1].trim() : '';
const coachingNote = coachingNoteMatch ? coachingNoteMatch[1].trim() : '';
const suggestedReframe = reframeMatch ? reframeMatch[1].trim() : '';

// Get clip data from previous node
const clipData = $('7. Code — Extract Objection Clips').item.json;

return [{
  json: {
    // Airtable fields
    callDate: clipData.callDate,
    repName: clipData.repName,
    contactName: clipData.contactName,
    companyName: clipData.companyName,
    callPurpose: clipData.callPurpose,
    objectionType: clipData.objectionType,
    objectionCategory,
    momentTitle: clipData.clipTitle,
    objectionDescription: `${whatHappened}\n\n${clipData.clipDescription}`,
    timestamp: `${clipData.timestampStart} — ${clipData.timestampEnd}`,
    relevanceScore: clipData.clipScore,
    repResponseAssessment,
    coachingNote,
    suggestedReframe,
    recordingUrl: clipData.recordingUrl,
    clipIndex: clipData.clipIndex
  }
}];
